"use client"

import { useState, useRef, useEffect, useCallback } from "react"
import {
  ImageIcon, Type, Download, Trash2, ZoomIn, ZoomOut,
  Grid3x3, Undo2, Redo2, Eye, Copy, Edit3, Layers,
  ChevronUp, ChevronDown, Bold, AlignLeft, AlignCenter, AlignRight,
  Sparkles, Move, Lock, Unlock, EyeOff, RefreshCw
} from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Card } from "@/components/ui/card"
import { Slider } from "@/components/ui/slider"
import { useToast } from "@/hooks/use-toast"
import { Badge } from "@/components/ui/badge"
import { Textarea } from "@/components/ui/textarea"
import { Separator } from "@/components/ui/separator"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { ScrollArea } from "@/components/ui/scroll-area"

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000"

interface Layer {
  layer_id: string
  type: "image" | "text"
  x: number
  y: number
  width?: number
  height?: number
  rotation: number
  opacity: number
  file_id?: string
  text?: string
  font_size?: number
  color?: string
  font_family?: string
  font_weight?: string
  text_align?: string
  visible?: boolean
  locked?: boolean
}

interface Project {
  _id: string
  width: number
  height: number
  background_color: string
  layers: Layer[]
}

const CANVAS_SIZES = [
  { label: "Instagram Square", value: "1080x1080" },
  { label: "Instagram Portrait", value: "1080x1350" },
  { label: "Instagram Story", value: "1080x1920" },
  { label: "Facebook Banner", value: "1200x628" },
  { label: "YouTube Thumbnail", value: "1280x720" },
  { label: "Display Ad", value: "728x90" },
]

const FONT_FAMILIES = ["Arial", "Georgia", "Courier New", "Verdana", "Times New Roman"]
const FONT_WEIGHTS = ["normal", "bold", "lighter"]

export default function EditorPage() {
  const [project, setProject] = useState<Project | null>(null)
  const [projectName, setProjectName] = useState("")
  const [showNameDialog, setShowNameDialog] = useState(true)
  const [selectedLayer, setSelectedLayer] = useState<Layer | null>(null)
  const [loading, setLoading] = useState(false)
  const [canvasSize, setCanvasSize] = useState({ width: 1080, height: 1080 })
  const [zoom, setZoom] = useState(0.5)
  const [showGrid, setShowGrid] = useState(false)
  const [editingText, setEditingText] = useState("")
  const [bgColor, setBgColor] = useState("#FFFFFF")
  const [dragging, setDragging] = useState<{ layerId: string; startX: number; startY: number; origX: number; origY: number } | null>(null)
  const [aiLoading, setAiLoading] = useState(false)
  const [aiSuggestions, setAiSuggestions] = useState<any[]>([])
  const [showAiPanel, setShowAiPanel] = useState(false)
  const [productNameAI, setProductNameAI] = useState("")
  const fileInputRef = useRef<HTMLInputElement>(null)
  const canvasRef = useRef<HTMLDivElement>(null)
  const { toast } = useToast()

  useEffect(() => {
    if (selectedLayer?.type === "text") setEditingText(selectedLayer.text || "")
  }, [selectedLayer])

  const api = async (endpoint: string, opts: RequestInit = {}) => {
    const res = await fetch(`${API_BASE}${endpoint}`, opts)
    if (!res.ok) {
      const err = await res.json().catch(() => ({ detail: "Request failed" }))
      throw new Error(err.detail || `HTTP ${res.status}`)
    }
    return res.json()
  }

  const initProject = async (name: string) => {
    setLoading(true)
    try {
      const params = new URLSearchParams({ width: String(canvasSize.width), height: String(canvasSize.height), background_color: bgColor })
      const result = await api(`/editor/create-project?${params}`, { method: "POST" })
      const projectData = await api(`/editor/${result.project_id}`)
      setProject(projectData)
      setProjectName(name)
      // persist to localStorage
      const saved = JSON.parse(localStorage.getItem("retailor_projects") || "[]")
      saved.push({ id: result.project_id, name, status: "active", createdAt: new Date().toISOString(), assetsCount: 0, progress: 0 })
      localStorage.setItem("retailor_projects", JSON.stringify(saved))
      toast({ title: "Project Created", description: `"${name}" is ready` })
    } catch (e: any) {
      toast({ title: "Error", description: e.message, variant: "destructive" })
    } finally {
      setLoading(false)
    }
  }

  const refreshProject = async () => {
    if (!project) return
    const updated = await api(`/editor/${project._id}`)
    setProject(updated)
    if (selectedLayer) {
      const refreshed = updated.layers.find((l: Layer) => l.layer_id === selectedLayer.layer_id)
      setSelectedLayer(refreshed || null)
    }
  }

  const handleAddImage = async (file: File) => {
    if (!project) return
    setLoading(true)
    try {
      const fd = new FormData()
      fd.append("file", file)
      fd.append("x", "50")
      fd.append("y", "50")
      fd.append("width", String(Math.min(400, canvasSize.width - 100)))
      fd.append("height", String(Math.min(400, canvasSize.height - 100)))
      await api(`/editor/${project._id}/add-image-layer`, { method: "POST", body: fd })
      await refreshProject()
      toast({ title: "Image Added" })
    } catch (e: any) {
      toast({ title: "Error", description: e.message, variant: "destructive" })
    } finally {
      setLoading(false)
    }
  }

  const handleAddText = async () => {
    if (!project) return
    setLoading(true)
    try {
      const params = new URLSearchParams({ text: "Double-click to edit", font_size: "48", color: "#000000", x: "100", y: "100" })
      await api(`/editor/${project._id}/add-text-layer?${params}`, { method: "POST" })
      await refreshProject()
      toast({ title: "Text Added" })
    } catch (e: any) {
      toast({ title: "Error", description: e.message, variant: "destructive" })
    } finally {
      setLoading(false)
    }
  }

  const handleUpdateLayer = useCallback(async (layerId: string, updates: Partial<Layer>) => {
    if (!project) return
    try {
      await api(`/editor/${project._id}/update-layer/${layerId}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(updates),
      })
      await refreshProject()
    } catch (e: any) {
      toast({ title: "Update failed", description: e.message, variant: "destructive" })
    }
  }, [project])

  const handleDeleteLayer = async (layerId: string) => {
    if (!project) return
    try {
      await api(`/editor/${project._id}/layer/${layerId}`, { method: "DELETE" })
      setSelectedLayer(null)
      await refreshProject()
      toast({ title: "Layer deleted" })
    } catch (e: any) {
      toast({ title: "Delete failed", description: e.message, variant: "destructive" })
    }
  }

  const handleExport = async (format: "png" | "jpeg" = "png") => {
    if (!project) return
    setLoading(true)
    try {
      const result = await api(`/editor/${project._id}/render`)
      const downloadUrl = `${API_BASE}/editor/rendered/${result.rendered_file_id}/download`
      const link = document.createElement("a")
      link.href = downloadUrl
      link.download = `${projectName || "creative"}.${format}`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      toast({ title: "Export Complete", description: `Downloaded as ${format.toUpperCase()}` })
    } catch (e: any) {
      toast({ title: "Export failed", description: e.message, variant: "destructive" })
    } finally {
      setLoading(false)
    }
  }

  const handleUndo = async () => {
    if (!project) return
    try {
      await api(`/editor/${project._id}/undo`, { method: "POST" })
      await refreshProject()
    } catch { toast({ title: "Nothing to undo" }) }
  }

  const handleRedo = async () => {
    if (!project) return
    try {
      await api(`/editor/${project._id}/redo`, { method: "POST" })
      await refreshProject()
    } catch { toast({ title: "Nothing to redo" }) }
  }

  // ── Drag handlers ──────────────────────────────────────────────────────────
  const onLayerMouseDown = (e: React.MouseEvent, layer: Layer) => {
    if (layer.locked) return
    e.stopPropagation()
    setSelectedLayer(layer)
    setDragging({ layerId: layer.layer_id, startX: e.clientX, startY: e.clientY, origX: layer.x, origY: layer.y })
  }

  const onCanvasMouseMove = (e: React.MouseEvent) => {
    if (!dragging || !project) return
    const dx = (e.clientX - dragging.startX) / zoom
    const dy = (e.clientY - dragging.startY) / zoom
    const newX = Math.round(dragging.origX + dx)
    const newY = Math.round(dragging.origY + dy)
    // Optimistic UI update
    setProject(prev => {
      if (!prev) return prev
      return {
        ...prev,
        layers: prev.layers.map(l => l.layer_id === dragging.layerId ? { ...l, x: newX, y: newY } : l)
      }
    })
    if (selectedLayer?.layer_id === dragging.layerId) {
      setSelectedLayer(prev => prev ? { ...prev, x: newX, y: newY } : prev)
    }
  }

  const onCanvasMouseUp = async () => {
    if (!dragging || !project) { setDragging(null); return }
    const layer = project.layers.find(l => l.layer_id === dragging.layerId)
    if (layer) {
      await handleUpdateLayer(dragging.layerId, { x: layer.x, y: layer.y })
    }
    setDragging(null)
  }

  // ── AI suggestions ─────────────────────────────────────────────────────────
  const fetchAISuggestions = async () => {
    if (!productNameAI.trim()) return
    setAiLoading(true)
    try {
      const res = await api("/ai/copy-suggestions", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ product_name: productNameAI, platform: "instagram", tone: "professional", num_variants: 3 }),
      })
      setAiSuggestions(res.variants || [])
    } catch (e: any) {
      toast({ title: "AI Error", description: e.message, variant: "destructive" })
    } finally {
      setAiLoading(false)
    }
  }

  const applyAISuggestion = async (variant: any) => {
    if (!project) return
    const params = new URLSearchParams({ text: variant.headline, font_size: "64", color: "#FFFFFF", x: "80", y: "80" })
    await api(`/editor/${project._id}/add-text-layer?${params}`, { method: "POST" })
    const params2 = new URLSearchParams({ text: variant.cta, font_size: "40", color: "#E94560", x: "80", y: "160" })
    await api(`/editor/${project._id}/add-text-layer?${params2}`, { method: "POST" })
    await refreshProject()
    toast({ title: "AI Copy Applied", description: `Headline and CTA added` })
  }

  // ── Render ─────────────────────────────────────────────────────────────────
  const renderLayerPreview = (layer: Layer) => {
    const isSelected = selectedLayer?.layer_id === layer.layer_id
    const style: React.CSSProperties = {
      position: "absolute",
      left: `${layer.x * zoom}px`,
      top: `${layer.y * zoom}px`,
      width: layer.width ? `${layer.width * zoom}px` : "auto",
      height: layer.height ? `${layer.height * zoom}px` : "auto",
      transform: `rotate(${layer.rotation}deg)`,
      opacity: layer.opacity ?? 1,
      cursor: layer.locked ? "not-allowed" : "move",
      userSelect: "none",
      outline: isSelected ? "2px solid #6366f1" : "none",
      outlineOffset: "2px",
      display: layer.visible === false ? "none" : undefined,
    }

    return (
      <div
        key={layer.layer_id}
        style={style}
        onMouseDown={(e) => onLayerMouseDown(e, layer)}
        onClick={(e) => { e.stopPropagation(); setSelectedLayer(layer) }}
      >
        {layer.type === "image" && layer.file_id && (
          // eslint-disable-next-line @next/next/no-img-element
          <img
            src={`${API_BASE}/asset/${layer.file_id}`}
            alt="layer"
            style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
            draggable={false}
            crossOrigin="anonymous"
            onError={(e) => { (e.currentTarget as HTMLImageElement).style.opacity = "0.3" }}
          />
        )}
        {layer.type === "text" && (
          <div
            style={{
              fontSize: `${(layer.font_size || 48) * zoom}px`,
              color: layer.color || "#000000",
              fontFamily: layer.font_family || "Arial",
              fontWeight: (layer.font_weight as any) || "bold",
              textAlign: (layer.text_align as any) || "left",
              whiteSpace: "pre-wrap",
              lineHeight: 1.2,
            }}
          >
            {layer.text || "Text"}
          </div>
        )}
        {isSelected && !layer.locked && (
          <div style={{ position: "absolute", inset: 0, border: "2px dashed #6366f1", pointerEvents: "none" }} />
        )}
      </div>
    )
  }

  return (
    <>
      {/* Name Dialog */}
      <Dialog open={showNameDialog} onOpenChange={setShowNameDialog}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Create New Project</DialogTitle>
            <DialogDescription>Set up your canvas to start designing</DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-2">
            <div className="space-y-1">
              <Label>Project Name</Label>
              <Input placeholder="e.g., Summer Sale Campaign" value={projectName} onChange={e => setProjectName(e.target.value)}
                onKeyDown={e => { if (e.key === "Enter" && projectName.trim()) { setShowNameDialog(false); initProject(projectName.trim()) }}} />
            </div>
            <div className="space-y-1">
              <Label>Canvas Size</Label>
              <Select value={`${canvasSize.width}x${canvasSize.height}`} onValueChange={v => { const [w, h] = v.split("x").map(Number); setCanvasSize({ width: w, height: h }) }}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>{CANVAS_SIZES.map(s => <SelectItem key={s.value} value={s.value}>{s.label} ({s.value})</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div className="space-y-1">
              <Label>Background Color</Label>
              <div className="flex gap-2">
                <input type="color" value={bgColor} onChange={e => setBgColor(e.target.value)} className="w-12 h-10 rounded border cursor-pointer" />
                <Input value={bgColor} onChange={e => setBgColor(e.target.value)} placeholder="#FFFFFF" />
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button onClick={() => { if (projectName.trim()) { setShowNameDialog(false); initProject(projectName.trim()) }}} disabled={!projectName.trim()} className="gradient-primary w-full">
              Create Project
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <div className="flex h-full overflow-hidden">
        {/* Left Sidebar — Tools */}
        <div className="w-64 shrink-0 border-r border-border bg-card flex flex-col overflow-hidden">
          <div className="p-3 border-b border-border">
            <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-2">Elements</p>
            <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={e => { if (e.target.files?.[0]) handleAddImage(e.target.files[0]); e.target.value = "" }} />
            <div className="space-y-1.5">
              <Button className="w-full gap-2 gradient-primary h-9" onClick={() => fileInputRef.current?.click()} disabled={!project || loading}>
                <ImageIcon className="h-4 w-4" /> Add Image
              </Button>
              <Button className="w-full gap-2 h-9 bg-transparent" variant="outline" onClick={handleAddText} disabled={!project || loading}>
                <Type className="h-4 w-4" /> Add Text
              </Button>
              <Button className="w-full gap-2 h-9 bg-transparent" variant="outline" onClick={() => setShowAiPanel(v => !v)} disabled={!project}>
                <Sparkles className="h-4 w-4 text-yellow-500" /> AI Copy
              </Button>
            </div>
          </div>

          {/* AI Copy Panel */}
          {showAiPanel && (
            <div className="p-3 border-b border-border bg-accent/5 space-y-2">
              <p className="text-xs font-semibold text-muted-foreground">AI Copy Generator</p>
              <Input placeholder="Product name..." value={productNameAI} onChange={e => setProductNameAI(e.target.value)} className="h-8 text-sm" />
              <Button size="sm" className="w-full gradient-primary h-8" onClick={fetchAISuggestions} disabled={aiLoading || !productNameAI.trim()}>
                {aiLoading ? <RefreshCw className="h-3 w-3 animate-spin mr-1" /> : <Sparkles className="h-3 w-3 mr-1" />}
                Generate
              </Button>
              {aiSuggestions.map((s, i) => (
                <div key={i} className="rounded border border-border p-2 text-xs space-y-1 bg-background">
                  <p className="font-bold">{s.headline}</p>
                  <p className="text-muted-foreground">{s.subheadline}</p>
                  <div className="flex gap-1 flex-wrap"><Badge variant="secondary">{s.cta}</Badge></div>
                  <Button size="sm" variant="ghost" className="w-full h-6 text-xs" onClick={() => applyAISuggestion(s)}>Apply →</Button>
                </div>
              ))}
            </div>
          )}

          {/* Layer Properties */}
          <ScrollArea className="flex-1">
            <div className="p-3 space-y-3">
              {selectedLayer ? (
                <>
                  <div className="flex items-center justify-between">
                    <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Properties</p>
                    <Button size="sm" variant="ghost" className="h-6 w-6 p-0 text-destructive" onClick={() => handleDeleteLayer(selectedLayer.layer_id)}>
                      <Trash2 className="h-3 w-3" />
                    </Button>
                  </div>

                  <div className="grid grid-cols-2 gap-1.5">
                    <div className="space-y-1"><Label className="text-xs">X</Label>
                      <Input type="number" className="h-8 text-xs" value={selectedLayer.x} onChange={e => handleUpdateLayer(selectedLayer.layer_id, { x: +e.target.value || 0 })} /></div>
                    <div className="space-y-1"><Label className="text-xs">Y</Label>
                      <Input type="number" className="h-8 text-xs" value={selectedLayer.y} onChange={e => handleUpdateLayer(selectedLayer.layer_id, { y: +e.target.value || 0 })} /></div>
                  </div>

                  {selectedLayer.type === "image" && (
                    <div className="grid grid-cols-2 gap-1.5">
                      <div className="space-y-1"><Label className="text-xs">W</Label>
                        <Input type="number" className="h-8 text-xs" value={selectedLayer.width || 0} onChange={e => handleUpdateLayer(selectedLayer.layer_id, { width: +e.target.value || 0 })} /></div>
                      <div className="space-y-1"><Label className="text-xs">H</Label>
                        <Input type="number" className="h-8 text-xs" value={selectedLayer.height || 0} onChange={e => handleUpdateLayer(selectedLayer.layer_id, { height: +e.target.value || 0 })} /></div>
                    </div>
                  )}

                  {selectedLayer.type === "text" && (
                    <div className="space-y-2">
                      <div className="space-y-1">
                        <Label className="text-xs">Text Content</Label>
                        <Textarea rows={2} className="text-xs resize-none" value={editingText}
                          onChange={e => setEditingText(e.target.value)}
                          onBlur={() => { if (editingText !== selectedLayer.text) handleUpdateLayer(selectedLayer.layer_id, { text: editingText }) }} />
                      </div>
                      <div className="space-y-1">
                        <Label className="text-xs">Font Size</Label>
                        <Input type="number" className="h-8 text-xs" value={selectedLayer.font_size || 48}
                          onChange={e => handleUpdateLayer(selectedLayer.layer_id, { font_size: +e.target.value || 12 })} />
                      </div>
                      <div className="space-y-1">
                        <Label className="text-xs">Font Family</Label>
                        <Select value={selectedLayer.font_family || "Arial"} onValueChange={v => handleUpdateLayer(selectedLayer.layer_id, { font_family: v })}>
                          <SelectTrigger className="h-8 text-xs"><SelectValue /></SelectTrigger>
                          <SelectContent>{FONT_FAMILIES.map(f => <SelectItem key={f} value={f}>{f}</SelectItem>)}</SelectContent>
                        </Select>
                      </div>
                      <div className="space-y-1">
                        <Label className="text-xs">Color</Label>
                        <div className="flex gap-1.5">
                          <input type="color" value={selectedLayer.color || "#000000"} className="w-10 h-8 rounded border cursor-pointer"
                            onChange={e => handleUpdateLayer(selectedLayer.layer_id, { color: e.target.value })} />
                          <Input value={selectedLayer.color || "#000000"} className="h-8 text-xs flex-1"
                            onChange={e => handleUpdateLayer(selectedLayer.layer_id, { color: e.target.value })} />
                        </div>
                      </div>
                      <div className="flex gap-1">
                        {(["left", "center", "right"] as const).map(a => (
                          <Button key={a} size="sm" variant={selectedLayer.text_align === a ? "secondary" : "ghost"} className="h-7 flex-1 p-0"
                            onClick={() => handleUpdateLayer(selectedLayer.layer_id, { text_align: a })}>
                            {a === "left" ? <AlignLeft className="h-3 w-3" /> : a === "center" ? <AlignCenter className="h-3 w-3" /> : <AlignRight className="h-3 w-3" />}
                          </Button>
                        ))}
                      </div>
                    </div>
                  )}

                  <div className="space-y-1">
                    <Label className="text-xs">Rotation ({selectedLayer.rotation}°)</Label>
                    <Slider value={[selectedLayer.rotation]} onValueChange={([v]) => handleUpdateLayer(selectedLayer.layer_id, { rotation: v })} min={-180} max={180} step={1} />
                  </div>
                  <div className="space-y-1">
                    <Label className="text-xs">Opacity ({Math.round((selectedLayer.opacity ?? 1) * 100)}%)</Label>
                    <Slider value={[(selectedLayer.opacity ?? 1) * 100]} onValueChange={([v]) => handleUpdateLayer(selectedLayer.layer_id, { opacity: v / 100 })} min={0} max={100} step={1} />
                  </div>
                </>
              ) : (
                <div className="text-center py-8 text-muted-foreground text-xs">
                  <Move className="h-8 w-8 mx-auto mb-2 opacity-30" />
                  <p>Click a layer to select it</p>
                </div>
              )}
            </div>
          </ScrollArea>

          {/* Actions */}
          <div className="p-3 border-t border-border space-y-1.5">
            <div className="flex gap-1">
              <Button className="flex-1 h-8 bg-transparent gap-1 text-xs" variant="outline" onClick={handleUndo} disabled={!project}><Undo2 className="h-3 w-3" />Undo</Button>
              <Button className="flex-1 h-8 bg-transparent gap-1 text-xs" variant="outline" onClick={handleRedo} disabled={!project}><Redo2 className="h-3 w-3" />Redo</Button>
            </div>
            <Button className="w-full h-9 gradient-primary gap-2" onClick={() => handleExport("png")} disabled={!project || loading}>
              <Download className="h-4 w-4" />{loading ? "Rendering..." : "Export PNG"}
            </Button>
            <Button className="w-full h-8 bg-transparent gap-2 text-xs" variant="outline" onClick={() => handleExport("jpeg")} disabled={!project || loading}>
              Export JPEG
            </Button>
          </div>
        </div>

        {/* Canvas Area */}
        <div className="flex-1 flex flex-col min-w-0">
          {/* Toolbar */}
          <div className="border-b border-border bg-card px-4 py-2 flex items-center gap-2 flex-wrap">
            {project && <Badge variant="secondary" className="text-xs">{projectName}</Badge>}
            <Separator orientation="vertical" className="h-5" />
            <Select value={`${canvasSize.width}x${canvasSize.height}`} onValueChange={v => { const [w, h] = v.split("x").map(Number); setCanvasSize({ width: w, height: h }) }}>
              <SelectTrigger className="w-44 h-8 text-xs"><SelectValue /></SelectTrigger>
              <SelectContent>{CANVAS_SIZES.map(s => <SelectItem key={s.value} value={s.value}>{s.label}</SelectItem>)}</SelectContent>
            </Select>
            <Separator orientation="vertical" className="h-5" />
            <Button variant="ghost" size="sm" className="h-8 w-8 p-0" onClick={() => setZoom(z => Math.max(0.1, +(z - 0.1).toFixed(1)))}><ZoomOut className="h-4 w-4" /></Button>
            <span className="text-xs w-10 text-center">{Math.round(zoom * 100)}%</span>
            <Button variant="ghost" size="sm" className="h-8 w-8 p-0" onClick={() => setZoom(z => Math.min(2, +(z + 0.1).toFixed(1)))}><ZoomIn className="h-4 w-4" /></Button>
            <Button variant="ghost" size="sm" className="h-8 w-8 p-0" onClick={() => setShowGrid(v => !v)}>
              <Grid3x3 className={`h-4 w-4 ${showGrid ? "text-primary" : ""}`} />
            </Button>
          </div>

          {/* Canvas + Layer Panel */}
          <div className="flex flex-1 min-h-0">
            <div
              className="flex-1 overflow-auto bg-muted/30 flex items-center justify-center p-8"
              onMouseMove={onCanvasMouseMove}
              onMouseUp={onCanvasMouseUp}
              onMouseLeave={onCanvasMouseUp}
            >
              {!project ? (
                <div className="text-center text-muted-foreground">
                  <Layers className="h-16 w-16 mx-auto mb-4 opacity-20" />
                  <p>Enter a project name above to start</p>
                </div>
              ) : (
                <div
                  ref={canvasRef}
                  className="relative shadow-2xl"
                  style={{
                    width: `${canvasSize.width * zoom}px`,
                    height: `${canvasSize.height * zoom}px`,
                    backgroundColor: project.background_color || "#FFFFFF",
                    backgroundImage: showGrid
                      ? `repeating-linear-gradient(0deg,#e5e7eb 0px,#e5e7eb 1px,transparent 1px,transparent ${20 * zoom}px),repeating-linear-gradient(90deg,#e5e7eb 0px,#e5e7eb 1px,transparent 1px,transparent ${20 * zoom}px)`
                      : undefined,
                    flexShrink: 0,
                  }}
                  onClick={() => setSelectedLayer(null)}
                >
                  {project.layers.map(renderLayerPreview)}
                </div>
              )}
            </div>

            {/* Right — Layer Panel */}
            {project && (
              <div className="w-48 shrink-0 border-l border-border bg-card flex flex-col">
                <div className="p-3 border-b border-border">
                  <p className="text-xs font-semibold text-muted-foreground uppercase tracking-wider flex items-center gap-1">
                    <Layers className="h-3 w-3" /> Layers
                  </p>
                </div>
                <ScrollArea className="flex-1">
                  <div className="p-2 space-y-1">
                    {[...project.layers].reverse().map((layer, idx) => (
                      <div
                        key={layer.layer_id}
                        className={`flex items-center gap-1.5 rounded px-2 py-1.5 cursor-pointer text-xs transition-colors ${selectedLayer?.layer_id === layer.layer_id ? "bg-primary/10 text-primary" : "hover:bg-muted/50"}`}
                        onClick={() => setSelectedLayer(layer)}
                      >
                        {layer.type === "image" ? <ImageIcon className="h-3 w-3 shrink-0" /> : <Type className="h-3 w-3 shrink-0" />}
                        <span className="flex-1 truncate">{layer.type === "text" ? (layer.text?.substring(0, 12) || "Text") : "Image"}</span>
                        <Button size="sm" variant="ghost" className="h-5 w-5 p-0 opacity-60 hover:opacity-100"
                          onClick={e => { e.stopPropagation(); handleUpdateLayer(layer.layer_id, { visible: layer.visible === false }) }}>
                          {layer.visible === false ? <EyeOff className="h-2.5 w-2.5" /> : <Eye className="h-2.5 w-2.5" />}
                        </Button>
                      </div>
                    ))}
                  </div>
                </ScrollArea>
              </div>
            )}
          </div>
        </div>
      </div>
    </>
  )
}
